import { v } from "convex/values";
import { httpAction, internalQuery, internalMutation } from "./_generated/server";
import type { ActionCtx } from "./_generated/server";
import { api, internal } from "./_generated/api";

// Payload interfaces for webhook events
interface WebhookPayload {
  event?: string;
  type?: string;
  data?: Record<string, unknown>;
  provider_id?: string;
  account_id?: string;
  from?: { identifier?: string };
  from_email?: string;
  thread_id?: string;
  id?: string;
  subject?: string;
  body_plain?: string;
  status?: string;
}

interface AccountCallbackPayload {
  account_id?: string;
  name?: string;
  identifier?: string;
}

// Unipile webhook receiver — handles new emails, tracking, account status
export const unipileWebhook = httpAction(async (ctx, request) => {
  // Verify Unipile-Auth shared secret (required)
  const secret = process.env.UNIPILE_WEBHOOK_SECRET;
  if (!secret) {
    console.error("UNIPILE_WEBHOOK_SECRET not configured - rejecting all webhooks");
    return new Response("Server misconfigured", { status: 500 });
  }

  const authHeader = request.headers.get("Unipile-Auth");
  if (!authHeader || authHeader !== secret) {
    console.error("Webhook auth failed: missing or invalid Unipile-Auth header");
    return new Response("Unauthorized", { status: 401 });
  }

  try {
    const payload = await request.json();
    const eventType = payload.event || payload.type;

    switch (eventType) {
      case "new_email":
      case "mail.received":
        await handleNewEmail(ctx, payload);
        break;

      case "email_tracking":
      case "mail.tracking":
        // Log open/click events — useful for analytics
        console.log("Email tracking event:", JSON.stringify(payload));
        break;

      case "account.status":
      case "account_status":
        await handleAccountStatus(ctx, payload);
        break;

      default:
        console.log("Unknown webhook event:", eventType, JSON.stringify(payload));
    }

    return new Response("OK", { status: 200 });
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : String(error);
    console.error("Webhook processing error:", message);
    return new Response("Internal error", { status: 500 });
  }
});

async function handleNewEmail(ctx: ActionCtx, payload: WebhookPayload) {
  const email = payload.data || payload;
  const providerId = email.provider_id
    ? JSON.stringify(email.provider_id)
    : "";
  const accountId = email.account_id || "";
  const from = email.from?.identifier || email.from_email || "";
  const threadId = email.thread_id || "";

  // Find the Unipile account to get the userId
  const account = accountId
    ? await ctx.runQuery(internal.webhook.findAccountByUnipileId, {
        unipileAccountId: accountId,
      })
    : null;

  if (!account) {
    console.log("No matching Unipile account for:", accountId);
    return;
  }

  // Check if this email is on a thread with an active enrollment
  if (threadId || providerId) {
    await ctx.runMutation(internal.webhook.processReply, {
      userId: account.userId,
      fromEmail: from,
      threadId,
      providerId,
      messageId: email.id || "",
      subject: email.subject || "",
      snippet: email.body_plain?.substring(0, 200) || "",
    });
  }
}

async function handleAccountStatus(ctx: ActionCtx, payload: WebhookPayload) {
  const data = payload.data || payload;
  const accountId = data.account_id || "";
  const status = data.status || "";

  if (status === "disconnected" || status === "error") {
    const account = await ctx.runQuery(
      internal.webhook.findAccountByUnipileId,
      { unipileAccountId: accountId }
    );

    if (account) {
      // Use the actual status from Unipile: "disconnected" vs "auth_expired"
      const convexStatus = status === "disconnected" ? "disconnected" : "auth_expired";
      await ctx.runMutation(internal.webhook.updateAccountStatus, {
        userId: account.userId,
        unipileAccountId: accountId,
        status: convexStatus,
      });
    }
  }
}

// Unipile account callback — called when user completes hosted auth
export const unipileAccountCallback = httpAction(async (ctx, request) => {
  try {
    const payload = await request.json();
    console.log("Unipile callback received:", JSON.stringify(payload));
    const accountId = payload.account_id || "";
    const rawName = payload.name || ""; // Encoded as "userId:PROVIDER" by requestConnectionLink
    const email = payload.identifier || "";

    // Parse userId and provider from the encoded name field
    let userId = rawName;
    let provider = "GOOGLE"; // Fallback for older links without encoded provider
    if (rawName.includes(":")) {
      const sepIndex = rawName.lastIndexOf(":");
      userId = rawName.substring(0, sepIndex);
      provider = rawName.substring(sepIndex + 1) || "GOOGLE";
    }

    if (!accountId || !userId) {
      return new Response("Missing account_id or name", { status: 400 });
    }

    await ctx.runMutation(internal.webhook.registerUnipileAccount, {
      userId,
      unipileAccountId: accountId,
      provider,
      email,
    });

    // Schedule backfill asynchronously (only for email providers)
    if (provider === "GOOGLE") {
      await ctx.scheduler.runAfter(0, api.unipile.backfillEmails, {
        userId,
        unipileAccountId: accountId,
      });
    }

    return new Response("OK", { status: 200 });
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : String(error);
    console.error("Account callback error:", message);
    return new Response("Internal error", { status: 500 });
  }
});

// --- Internal functions used by webhook handlers ---

export const findAccountByUnipileId = internalQuery({
  args: { unipileAccountId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("unipileAccounts")
      .withIndex("by_unipile_id", (q) =>
        q.eq("unipileAccountId", args.unipileAccountId)
      )
      .first();
  },
});

export const processReply = internalMutation({
  args: {
    userId: v.string(),
    fromEmail: v.string(),
    threadId: v.string(),
    providerId: v.string(),
    messageId: v.string(),
    subject: v.optional(v.string()),
    snippet: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    // Deduplicate by messageId: skip if we already processed this message
    if (args.messageId) {
      const existingReply = await ctx.db
        .query("replyEvents")
        .withIndex("by_thread", (q) =>
          q.eq("userId", args.userId).eq("threadId", args.threadId)
        )
        .collect();
      const alreadyProcessed = existingReply.some((r) => r.messageId === args.messageId);
      if (alreadyProcessed) {
        console.log(`Duplicate messageId ${args.messageId} for user ${args.userId}, skipping`);
        return;
      }
    }

    // Find active enrollments for this contact
    const enrollments = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_contact", (q) =>
        q.eq("userId", args.userId).eq("contactEmail", args.fromEmail)
      )
      .collect();

    const activeEnrollments = enrollments.filter(
      (e) => e.status === "active" || e.status === "paused"
    );

    if (activeEnrollments.length === 0) return;

    // Get sync version
    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    // Stop ALL active enrollments for this contact
    for (const enrollment of activeEnrollments) {
      await ctx.db.patch(enrollment._id, {
        status: "stopped",
        statusReason: "reply received",
        replyState: "needs_classification",
        lastReplyAt: new Date().toISOString(),
        nextDueAt: "",
        syncVersion: version,
      });

      // Cancel all pending tasks
      const tasks = await ctx.db
        .query("followUpTasks")
        .withIndex("by_enrollment", (q) =>
          q.eq("enrollmentId", enrollment.externalId)
        )
        .collect();

      for (const task of tasks) {
        if (task.status === "open") {
          await ctx.db.patch(task._id, {
            status: "canceled",
            sendStatus: "canceled",
            canceledReason: "reply received",
            syncVersion: version,
          });
        }
      }

      // Cancel pending drafts
      const drafts = await ctx.db
        .query("sequenceDrafts")
        .withIndex("by_enrollment", (q) =>
          q.eq("enrollmentId", enrollment.externalId)
        )
        .collect();

      for (const draft of drafts) {
        if (draft.status === "pending") {
          await ctx.db.patch(draft._id, {
            status: "canceled",
            syncVersion: version,
          });
        }
      }

      // Record reply event
      const replyId = `re-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      await ctx.db.insert("replyEvents", {
        externalId: replyId,
        enrollmentId: enrollment.externalId,
        mailboxId: enrollment.mailboxId,
        threadId: args.threadId,
        messageId: args.messageId,
        contactEmail: args.fromEmail,
        classification: "needs_classification",
        subject: args.subject,
        snippet: args.snippet,
        occurredAt: new Date().toISOString(),
        syncVersion: version,
        userId: args.userId,
      });

      version++;
    }

    // Update sync state
    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: version,
      });
    }
  },
});

export const updateAccountStatus = internalMutation({
  args: { userId: v.string(), unipileAccountId: v.string(), status: v.string() },
  handler: async (ctx, args) => {
    const account = await ctx.db
      .query("unipileAccounts")
      .withIndex("by_unipile_id", (q) =>
        q.eq("unipileAccountId", args.unipileAccountId)
      )
      .first();

    if (account) {
      // Verify ownership: account must belong to the specified user
      if (account.userId !== args.userId) {
        console.error(
          `Ownership mismatch: account ${args.unipileAccountId} belongs to ${account.userId}, not ${args.userId}`
        );
        return;
      }
      await ctx.db.patch(account._id, { status: args.status });
    }

    // Find mailboxes associated with this account's email and mark them
    const email = account?.email;
    const mailboxes = email
      ? await ctx.db
          .query("mailboxes")
          .withIndex("by_email", (q) =>
            q.eq("userId", args.userId).eq("email", email)
          )
          .collect()
      : [];

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    let version = (syncState?.lastSyncVersion ?? 0) + 1;

    const affectedMailboxIds: string[] = [];

    for (const mailbox of mailboxes) {
      if (mailbox.status === "active") {
        await ctx.db.patch(mailbox._id, {
          status: "auth_expired",
          syncVersion: version,
        });
        affectedMailboxIds.push(mailbox.externalId);
        version++;
      }
    }

    // Pause active enrollments on affected mailboxes
    const statusReason = args.status === "disconnected"
      ? "account disconnected"
      : "account auth expired";

    for (const mailboxId of affectedMailboxIds) {
      const enrollments = await ctx.db
        .query("sequenceEnrollments")
        .withIndex("by_status", (q) =>
          q.eq("userId", args.userId).eq("status", "active")
        )
        .collect();

      for (const enrollment of enrollments) {
        if (enrollment.mailboxId !== mailboxId) continue;

        await ctx.db.patch(enrollment._id, {
          status: "paused",
          statusReason,
          syncVersion: version,
        });
        version++;

        // Cancel pending tasks for this enrollment
        const tasks = await ctx.db
          .query("followUpTasks")
          .withIndex("by_enrollment", (q) =>
            q.eq("enrollmentId", enrollment.externalId)
          )
          .collect();

        for (const task of tasks) {
          if (task.status === "open" && task.sendStatus === "pending") {
            await ctx.db.patch(task._id, {
              sendStatus: "canceled",
              canceledReason: statusReason,
              syncVersion: version,
            });
            version++;
          }
        }
      }
    }

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: version,
      });
    }
  },
});

export const registerUnipileAccount = internalMutation({
  args: {
    userId: v.string(),
    unipileAccountId: v.string(),
    provider: v.string(),
    email: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    // Check if this exact Unipile account ID already exists
    const existingById = await ctx.db
      .query("unipileAccounts")
      .withIndex("by_unipile_id", (q) =>
        q.eq("unipileAccountId", args.unipileAccountId)
      )
      .first();

    if (existingById) {
      await ctx.db.patch(existingById._id, {
        status: "connected",
        email: args.email,
      });
    } else {
      // Check if user already has an account for this provider (dedup by userId+provider)
      // This prevents duplicate entries when a user reconnects the same provider
      const existingByProvider = await ctx.db
        .query("unipileAccounts")
        .withIndex("by_provider", (q) =>
          q.eq("userId", args.userId).eq("provider", args.provider)
        )
        .first();

      if (existingByProvider) {
        // Update the existing record with the new Unipile account ID
        await ctx.db.patch(existingByProvider._id, {
          unipileAccountId: args.unipileAccountId,
          status: "connected",
          email: args.email,
          connectedAt: new Date().toISOString(),
        });
      } else {
        await ctx.db.insert("unipileAccounts", {
          userId: args.userId,
          provider: args.provider,
          unipileAccountId: args.unipileAccountId,
          email: args.email,
          status: "connected",
          connectedAt: new Date().toISOString(),
        });
      }
    }

    // Auto-create mailbox if one doesn't exist for this email
    const email = args.email;
    if (email) {
      const existingMailbox = await ctx.db
        .query("mailboxes")
        .withIndex("by_email", (q) =>
          q.eq("userId", args.userId).eq("email", email)
        )
        .first();

      if (!existingMailbox) {
        const syncState = await ctx.db
          .query("syncState")
          .withIndex("by_user", (q) => q.eq("userId", args.userId))
          .first();
        const version = (syncState?.lastSyncVersion ?? 0) + 1;

        const mailboxId = `mbx-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
        await ctx.db.insert("mailboxes", {
          externalId: mailboxId,
          email,
          provider: args.provider,
          status: "active",
          firstTouchDailyCap: 25,
          followUpDailyCap: 50,
          replyDailyCap: 100,
          minGapMinutes: 3,
          sendWindowStartHour: 8,
          sendWindowEndHour: 18,
          sendWindowTimezone: "America/New_York",
          syncVersion: version,
          userId: args.userId,
        });

        if (syncState) {
          await ctx.db.patch(syncState._id, { lastSyncVersion: version });
        } else {
          await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
        }
      } else if (existingMailbox.status !== "active") {
        await ctx.db.patch(existingMailbox._id, { status: "active" });
      }

      // Resume enrollments that were paused due to disconnect/auth expiry
      const mailbox = existingMailbox || await ctx.db
        .query("mailboxes")
        .withIndex("by_email", (q) =>
          q.eq("userId", args.userId).eq("email", email)
        )
        .first();

      if (mailbox) {
        const pausedEnrollments = await ctx.db
          .query("sequenceEnrollments")
          .withIndex("by_status", (q) =>
            q.eq("userId", args.userId).eq("status", "paused")
          )
          .collect();

        const syncState = await ctx.db
          .query("syncState")
          .withIndex("by_user", (q) => q.eq("userId", args.userId))
          .first();
        let version = (syncState?.lastSyncVersion ?? 0) + 1;
        let updated = false;

        for (const enrollment of pausedEnrollments) {
          if (enrollment.mailboxId !== mailbox.externalId) continue;
          if (enrollment.statusReason !== "account disconnected" && enrollment.statusReason !== "account auth expired") continue;

          await ctx.db.patch(enrollment._id, {
            status: "active",
            statusReason: "account reconnected",
            syncVersion: version,
          });
          version++;
          updated = true;

          // Re-enable tasks that were canceled due to the disconnect
          const tasks = await ctx.db
            .query("followUpTasks")
            .withIndex("by_enrollment", (q) =>
              q.eq("enrollmentId", enrollment.externalId)
            )
            .collect();

          for (const task of tasks) {
            if (task.status === "open" && task.sendStatus === "canceled"
                && (task.canceledReason === "account disconnected" || task.canceledReason === "account auth expired")) {
              await ctx.db.patch(task._id, {
                sendStatus: "pending",
                canceledReason: undefined,
                syncVersion: version,
              });
              version++;
            }
          }
        }

        if (updated) {
          if (syncState) {
            await ctx.db.patch(syncState._id, { lastSyncVersion: version });
          } else {
            await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
          }
        }
      }
    }
  },
});

